llint segche(llint l, llint r) {
	llint lli = 39000;
	
	for (llint i = 0; i < r-l; i++) {
		rli[i].clear();
		//rli[i].shrink_to_fit();
	}
	for (llint i = 0; i < lli; i++) {
		segche_li[i] = false;
	}

	for (llint i = 2; i < lli; i++) {
		if (!segche_li[i]) {
			llint st = i << 1;
			for (llint j = st; j < lli; j += i) {
				segche_li[j] = 1;
				//if (segche_li22[j] != 0 and segche_li22[j] != i) segche_li2[j] = 1;
				//segche_li22[j] = i;
			}
			llint i2 = 1;
			for (llint k = 0; k < 50; k += 1) {
				i2 *= i;
				if (i2 >= r) break;
				st = max(i2,((l - 1) / i2 + 1) * i2);
				for (llint j = st; j < r; j += i2) {
					rli[j - l].push_back(i);
				}
			}
		}
		//else if(!segche_li2[i]) {
		//	llint st = ((l - 1) / i + 1) * i;
		//	for (llint j = st; j < r; j += i) {
		//		rli[j - l].push_back(segche_li22[i]);
		//	}
		//}
	}

	return 0;
}

