			llint ret2 = 1;
			if (dum != i) ret2 = 3;
			for (llint j = 0; j < rli[i - l].size(); j++) {
				sol2_li[rli[i - l][j]] += 1;
			}
			for (llint j = 0; j < rli[i - l].size(); j++) {
				if (sol2_li[rli[i - l][j]] != 0) {
					ret2 *= ncck_p[sol2_li[rli[i - l][j]]-1];
					sol2_li[rli[i - l][j]] = 0;
				}
			}
			ret += ret2;


